+
+const ENV_PROVIDER_SOURCES: EnvProviderSource[] = [
+	{
+		kind: "anthropic",
+		id: "anthropic",
+		label: "Anthropic",
+		envKeys: ["ANTHROPIC_API_KEY"],
+	},
+	{
+		kind: "openai",
